		long deltaCountMinBytes = usable * 15L / 100L;
		long directoryBytes = usable * 25L / 100L;
		long coldBytes = usable - baseCountMinBytes - deltaCountMinBytes - directoryBytes;
		int depth = 4;
		int baseWidth = floorPowerOfTwo(baseCountMinBytes / (TABLES * depth * Long.BYTES));
		int deltaWidth = floorPowerOfTwo(deltaCountMinBytes / (TABLES * depth * Long.BYTES));
		int witnesses = 8;
		long directoryEntryBytes = 64L + witnesses * 5L * Long.BYTES;
		int directoryCapacity = boundedInt(Math.max(1L, directoryBytes / directoryEntryBytes));
		int maximumCold = boundedInt(coldBytes / (5L * Long.BYTES));
		int coldCapacity = Math.min(requestedColdSampleCapacity, maximumCold);
		long unusedColdBytes = coldBytes - (long) coldCapacity * 5L * Long.BYTES;
		int deltaSampleCapacity = boundedInt(Math.max(1L, unusedColdBytes / (5L * Long.BYTES)));
